const express = require('express');
const multer  = require('multer');
const path    = require('path');
const fs      = require('fs');
const db      = require('../database');
const router  = express.Router();

// Configurar almacenamiento de imágenes
const storage = multer.diskStorage({
    destination: (req, file, cb) => {
        const uploadDir = path.join(__dirname, '..', 'uploads');
        if (!fs.existsSync(uploadDir)) fs.mkdirSync(uploadDir);
        cb(null, uploadDir);
    },
    filename: (req, file, cb) => {
        const unique = Date.now() + '-' + Math.round(Math.random() * 1e9);
        cb(null, unique + path.extname(file.originalname));
    }
});

const upload = multer({
    storage,
    limits: { fileSize: 10 * 1024 * 1024 }, // 10MB
    fileFilter: (req, file, cb) => {
        const allowed = /jpeg|jpg|png|gif/;
        const ok = allowed.test(file.mimetype) && allowed.test(path.extname(file.originalname).toLowerCase());
        ok ? cb(null, true) : cb(new Error('Solo se permiten imágenes'));
    }
});

// GET /api/posts — obtener todos los posts
router.get('/', (req, res) => {
    const posts = db.prepare(`SELECT * FROM posts ORDER BY scheduled_at ASC`).all();
    res.json({ success: true, posts });
});

// POST /api/posts — crear nuevo post
router.post('/', upload.single('image'), (req, res) => {
    const { text, scheduled_at, instagram, facebook } = req.body;

    if (!scheduled_at) {
        return res.status(400).json({ success: false, error: 'La fecha es requerida' });
    }
    if (!instagram && !facebook) {
        return res.status(400).json({ success: false, error: 'Selecciona al menos una red social' });
    }
    if (new Date(scheduled_at) <= new Date()) {
        return res.status(400).json({ success: false, error: 'La fecha debe ser futura' });
    }

    const imageUrl = req.file
        ? `http://localhost:${process.env.PORT || 3000}/uploads/${req.file.filename}`
        : null;

    const result = db.prepare(`
        INSERT INTO posts (text, image_url, scheduled_at, instagram, facebook, status)
        VALUES (?, ?, ?, ?, ?, 'scheduled')
    `).run(
        text || '',
        imageUrl,
        scheduled_at,
        instagram === 'true' || instagram === true ? 1 : 0,
        facebook  === 'true' || facebook  === true ? 1 : 0
    );

    const post = db.prepare(`SELECT * FROM posts WHERE id = ?`).get(result.lastInsertRowid);
    res.json({ success: true, post });
});

// DELETE /api/posts/:id — eliminar post
router.delete('/:id', (req, res) => {
    const post = db.prepare(`SELECT * FROM posts WHERE id = ?`).get(req.params.id);
    if (!post) return res.status(404).json({ success: false, error: 'Post no encontrado' });

    // Eliminar imagen si existe
    if (post.image_url) {
        const filename = post.image_url.split('/uploads/')[1];
        const filepath = path.join(__dirname, '..', 'uploads', filename);
        if (fs.existsSync(filepath)) fs.unlinkSync(filepath);
    }

    db.prepare(`DELETE FROM posts WHERE id = ?`).run(req.params.id);
    res.json({ success: true });
});

module.exports = router;
